-- ------------------------------------------------------------
-- File: 20260630120000_fortnox_refresh_lock.sql
-- ------------------------------------------------------------

-- Fortnox rotates the refresh_token on every use and immediately invalidates the
-- previous one. In a serverless environment, concurrent requests run in separate
-- processes that can each read the same stale refresh_token and race to use it —
-- the loser gets invalid_grant, which previously surfaced as "Fortnox-anslutningen
-- har upphört att gälla" and required a full manual reconnect even though the
-- connection itself was fine. This column lets refreshAccessTokenForUser claim an
-- exclusive cross-process lock (via an atomic UPDATE ... WHERE) before calling
-- Fortnox, so only one process ever rotates the token at a time; others wait and
-- read back the winner's result instead of racing.
ALTER TABLE public.fortnox_connections
  ADD COLUMN IF NOT EXISTS refreshing_at timestamptz;


-- ------------------------------------------------------------
-- File: 20260630130000_customer_company_name.sql
-- ------------------------------------------------------------

-- Optional company name for a job's customer. When set, this is the
-- official/Fortnox-facing name (customer_name resolves to this value);
-- when empty, customer_name falls back to the personal first/last name.

ALTER TABLE public.jobs
  ADD COLUMN IF NOT EXISTS customer_company_name TEXT;


-- ------------------------------------------------------------
-- File: 20260701120000_invoice_bookkept_at.sql
-- ------------------------------------------------------------

-- Track when an invoice was actually bookkept in Fortnox, distinct from
-- invoice_booked_at (which is set for every finalize action — book, send,
-- or book_send — regardless of whether bookkeeping actually happened).
ALTER TABLE public.jobs
  ADD COLUMN IF NOT EXISTS invoice_bookkept_at timestamptz;


-- ------------------------------------------------------------
-- File: 20260702090000_fortnox_refresh_events.sql
-- ------------------------------------------------------------

-- Persistent audit trail for Fortnox token refreshes.
--
-- Fortnox rotates the refresh_token on every use and immediately invalidates
-- the previous one. If the serverless process is killed between Fortnox
-- rotating the token and us persisting the new one (e.g. the Netlify function
-- timeout fires mid-request), the connection is permanently wedged — and a
-- dead process can never write a console log, so Netlify function logs cannot
-- capture this failure mode at all. This table can: a row is inserted BEFORE
-- the token call and updated after it finishes, so a row whose finished_at is
-- NULL means the process died mid-rotation. Rows survive Netlify's short log
-- retention and are queryable long after the fact.
CREATE TABLE IF NOT EXISTS public.fortnox_refresh_events (
  id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  user_id uuid NOT NULL,
  -- what caused the refresh: 'expiry-buffer' (proactive) or '401-retry'
  trigger_reason text NOT NULL,
  attempt integer NOT NULL DEFAULT 0,
  -- sha256 prefix of the refresh_token used, to prove WHICH token was spent
  token_fingerprint text,
  -- expires_at of the connection before this refresh ran
  old_expires_at timestamptz,
  started_at timestamptz NOT NULL DEFAULT now(),
  finished_at timestamptz,
  -- 'success' | 'token-error' (Fortnox rejected/failed the token call)
  -- | 'store-error' (Fortnox rotated the token but the DB write failed — the
  --   dangerous wedge case). NULL with finished_at NULL = process died mid-flight.
  outcome text,
  error_status integer,
  error_body text,
  duration_ms integer
);

-- Server-only table: RLS enabled with no policies, so only the service role
-- (which bypasses RLS) can read or write it.
ALTER TABLE public.fortnox_refresh_events ENABLE ROW LEVEL SECURITY;

CREATE INDEX IF NOT EXISTS fortnox_refresh_events_user_started_idx
  ON public.fortnox_refresh_events (user_id, started_at DESC);


-- ------------------------------------------------------------
-- File: 20260702153000_fortnox_refresh_cron.sql
-- ------------------------------------------------------------

-- Schedules the fortnox-refresh Edge Function to run every 5 minutes, so
-- Fortnox token rotation happens on a background timer instead of inline
-- during a live user request. See supabase/functions/fortnox-refresh/index.ts
-- for why: a live-request refresh can be frozen/killed by the serverless
-- runtime after Fortnox has already rotated the token but before we saved
-- it, permanently wedging the connection — confirmed in production on
-- 2026-07-02 via the fortnox_refresh_events audit trail.
CREATE EXTENSION IF NOT EXISTS pg_cron WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS pg_net WITH SCHEMA extensions;

-- The shared secret the cron job sends (as `x-cron-secret`) so the Edge
-- Function can verify the call actually came from our own pg_cron and not an
-- arbitrary internet request. The secret's VALUE is intentionally not in this
-- file — it lives in Supabase Vault (`select vault.create_secret(...)`, run
-- once directly against the project, not checked into git) under the name
-- 'fortnox_cron_secret', and must match the Edge Function's CRON_SECRET
-- secret (`supabase secrets set CRON_SECRET=...`). Setting up a new
-- environment requires creating both by hand.
SELECT cron.schedule(
  'fortnox-token-refresh',
  '*/5 * * * *',
  $$
  SELECT net.http_post(
    url := 'https://YOUR_PROJECT_REF.supabase.co/functions/v1/fortnox-refresh',
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'x-cron-secret', (SELECT decrypted_secret FROM vault.decrypted_secrets WHERE name = 'fortnox_cron_secret' LIMIT 1)
    ),
    body := '{}'::jsonb,
    timeout_milliseconds := 20000
  );
  $$
);


-- ------------------------------------------------------------
-- File: 20260703120000_welcome_sms_and_quote_notifications.sql
-- ------------------------------------------------------------

-- Two related notification/SMS improvements.
--
-- 1) link_sms_sent_at on jobs: tracks when the introductory "here is your
--    link / how to log in" SMS was sent to the customer. The very first
--    outbound SMS on a job must always be this welcome message, so later
--    status/quote/chat SMS check this column and send the welcome first when
--    it hasn't gone out yet (e.g. the workshop added the phone number only
--    when sending a quote). Existing jobs are backfilled to created_at so
--    customers already mid-flow don't receive a fresh welcome SMS.
--
-- 2) notify_quote_responses on profiles: workshop-level toggle for the push
--    notification sent to every account in the workshop when a customer
--    approves (or rejects) a quote. Defaults on.

ALTER TABLE public.jobs
  ADD COLUMN IF NOT EXISTS link_sms_sent_at timestamptz;

UPDATE public.jobs
  SET link_sms_sent_at = created_at
  WHERE link_sms_sent_at IS NULL;

ALTER TABLE public.profiles
  ADD COLUMN IF NOT EXISTS notify_quote_responses boolean NOT NULL DEFAULT true;


-- ------------------------------------------------------------
-- File: 20260707200000_invoice_snapshot.sql
-- ------------------------------------------------------------

-- Frozen snapshot of everything the invoice PDF render needs, captured once
-- when the invoice is booked/sent: the full Fortnox invoice as it existed at
-- that moment plus the workshop's company details (name, address, bank
-- details, logo). Opening the invoice later re-renders from this snapshot —
-- same pipeline as "Förhandsgranska" — so the customer always sees the
-- document as issued, no matter how profile data or render code change later.
ALTER TABLE public.jobs
  ADD COLUMN IF NOT EXISTS invoice_snapshot jsonb;


-- ------------------------------------------------------------
-- File: 20260707210000_client_diagnostics.sql
-- ------------------------------------------------------------

-- Temporary diagnostics sink for the open-invoice investigation: the failure
-- reloads the page on the phone, destroying any client-side evidence, so each
-- step is beaconed to the server and stored here. Read via
-- /api/public/client-log?key=... . Drop the table when the bug is fixed.
CREATE TABLE IF NOT EXISTS public.client_diagnostics (
  id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  created_at timestamptz NOT NULL DEFAULT now(),
  session text,
  step text NOT NULL,
  detail text
);
-- Service-role access only (no policies on purpose).
ALTER TABLE public.client_diagnostics ENABLE ROW LEVEL SECURITY;
